proof fn phi_1_tla_exists_proved_by_witness_closure_bridge(ex: Execution<int>, a_to_p: spec_fn(int) -> TempPred<int>, witness_a: int)
    requires
        a_to_p(witness_a).satisfied_by(ex),
    ensures
        tla_exists(a_to_p).satisfied_by(ex),
{
    tla_exists_proved_by_witness::<int, int>(ex, a_to_p, witness_a);
}

proof fn phi_2_temp_pred_equality_intensional_bridge(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
    ensures
        p == q,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_3_mutual_entailment_derives_false_if_distinct(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
        p !== q,
    ensures
        false,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_4_tla_exists_or_equality_bridge(a_to_p: spec_fn(int) -> TempPred<int>, q: TempPred<int>)
    ensures
        tla_exists(|a: int| a_to_p(a).or(q)) == tla_exists(a_to_p).or(q),
{
    tla_exists_or_equality::<int, int>(a_to_p, q);
}

proof fn phi_5_arbitrary_witness_in_else_branch(ex: Execution<int>, a_to_p: spec_fn(int) -> TempPred<int>, q: TempPred<int>)
    requires
        q.satisfied_by(ex),
        !tla_exists(a_to_p).satisfied_by(ex),
    ensures
        tla_exists(|a: int| a_to_p(a).or(q)).satisfied_by(ex),
{
    tla_exists_or_equality::<int, int>(a_to_p, q);
}
